export const getIntegrationBrand = (name: string) => integrationBrands[name];

export type IntegrationCategory = {
  id: IntegrationCategoryId;
  title: string;
  description: string;
  systems: IntegrationSystem[];
};

const makeSystem = (
  categoryId: IntegrationCategoryId,
  category: string,
  name: string,
  short: string,
  color: string,
  description: string,
  useCases: string[],
  workflows: string[],
): IntegrationSystem => ({
  name,
  slug: `${name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "")}-office-add-in-integration`,
  short,
  color,
  categoryId,
  category,
  description,
  useCases,
  workflows,
});

